483	+func BuildProviderSnapshot(ctx context.Context, repo, providerVersion string) (ProviderSnapshot, error) {
484	+	absRepo, err := filepath.Abs(repo)
485	+	if err != nil {
486	+		return ProviderSnapshot{}, err
487	+	}
488	+	repoKey := repoKey(absRepo)
489	+	commit, _ := gitutil.RevParse(ctx, absRepo, "HEAD")
490	+	tree, _ := gitutil.RevParse(ctx, absRepo, "HEAD^{tree}")
491	+
492	+	paths, err := workingTreeFiles(absRepo)
493	+	if err != nil {
494	+		return ProviderSnapshot{}, err
495	+	}
496	+
497	+	parser := TreeSitterParser{}
498	+	languageSet := map[string]struct{}{}
499	+	var files []FileRecord
500	+	var symbols []SymbolRecord
501	+	var failures []PartialFailure
502	+	recordsByFile := map[string][]SymbolRecord{}
503	+
504	+	for _, path := range paths {
505	+		if !Supported(path) {
506	+			continue
507	+		}
508	+		content, err := os.ReadFile(filepath.Join(absRepo, filepath.FromSlash(path)))
509	+		if err != nil {
510	+			failures = append(failures, PartialFailure{
511	+				Code:                 "E_FILE_READ",
512	+				Severity:             "error",
513	+				FilePath:             path,
514	+				EffectOnCompleteness: "file omitted from semantic snapshot",
515	+				Detail:               err.Error(),
516	+			})
517	+			continue
518	+		}
519	+		entities, language := parser.Parse(path, string(content))
520	+		if language == "" {
521	+			failures = append(failures, PartialFailure{
522	+				Code:                 "E_UNSUPPORTED_LANGUAGE",
523	+				Severity:             "warning",
524	+				FilePath:             path,
525	+				EffectOnCompleteness: "file omitted because no parser is available",
526	+			})
527	+			continue
528	+		}
529	+		languageSet[language] = struct{}{}
530	+		files = append(files, FileRecord{
531	+			RecordType: "file",
532	+			Path:       path,
533	+			Blob:       contentHash(content),
534	+			Language:   language,
535	+			Bytes:      len(content),
536	+		})
537	+		fileSymbols := entitySymbols(repoKey, path, language, entities)
538	+		symbols = append(symbols, fileSymbols...)
539	+		recordsByFile[path] = fileSymbols
540	+	}
541	+
542	+	relations := buildRelations(repoKey, absRepo, files, recordsByFile)
543	+	languages := sortedKeys(languageSet)
544	+	if failures == nil {
545	+		failures = []PartialFailure{}
546	+	}
547	+	header := SnapshotHeader{
548	+		SchemaVersion:   SchemaVersion,
549	+		Provider:        ProviderName,
550	+		ProviderVersion: providerVersion,
551	+		RepoRoot:        absRepo,
552	+		RepoKey:         repoKey,
553	+		Commit:          commit,
554	+		Tree:            tree,
555	+		Languages:       languages,
556	+		Capabilities:    []string{"ndjson", "stable-symbol-id-v1", "local-only", "partial-failures"},
557	+		Warnings:        []ProviderWarning{},
558	+		PartialFailures: failures,
559	+		Stats: ProviderStats{
560	+			Files:             len(files),
561	+			ParsedFiles:       len(recordsByFile),
562	+			Symbols:           len(symbols),
563	+			Relations:         len(relations),
564	+			PartialFailures:   len(failures),
565	+			CompletenessLevel: completenessLevel(len(failures), len(files)),
566	+		},
567	+	}
568	+	return ProviderSnapshot{Header: header, Files: files, Symbols: symbols, Relations: relations}, nil
569	+}
