611	+func entitySymbols(repoKey, path, language string, entities []Entity) []SymbolRecord {
612	+	byName := map[string]string{}
613	+	var symbols []SymbolRecord
614	+	for _, entity := range entities {
615	+		qualified := entity.Name
616	+		id := symbolID(repoKey, language, path, entity.Kind, qualified)
617	+		containerID := ""
618	+		if containerName := containerName(qualified); containerName != "" {
619	+			if parentID, ok := byName[containerName]; ok {
620	+				containerID = parentID
621	+			}
622	+		}
623	+		symbol := SymbolRecord{
624	+			RecordType:      "symbol",
625	+			ID:              id,
626	+			StableIDVersion: StableSymbolIDVersion,
627	+			Kind:            entity.Kind,
628	+			Name:            shortEntityName(entity.Name),
629	+			QualifiedName:   qualified,
630	+			FilePath:        path,
631	+			StartLine:       entity.StartLine,
632	+			EndLine:         entity.EndLine,
633	+			Signature:       entity.Signature,
634	+			BodyHash:        entity.BodyHash,
635	+			Language:        language,
636	+			ContainerID:     containerID,
637	+		}
638	+		symbols = append(symbols, symbol)
639	+		byName[qualified] = id
640	+	}
641	+	return symbols
642	+}
