644	+func buildRelations(repoKey, repo string, files []FileRecord, recordsByFile map[string][]SymbolRecord) []RelationRecord {
645	+	var relations []RelationRecord
646	+	symbolsByShortName := map[string][]SymbolRecord{}
647	+	for _, records := range recordsByFile {
648	+		for _, symbol := range records {
649	+			relations = append(relations, RelationRecord{
650	+				RecordType:   "relation",
651	+				FromID:       fileID(repoKey, symbol.FilePath),
652	+				ToID:         symbol.ID,
653	+				Type:         "DEFINES",
654	+				Confidence:   1,
655	+				Reason:       "symbol parsed from file",
656	+				WarningCodes: []string{},
657	+			})
658	+			if symbol.ContainerID != "" {
659	+				relations = append(relations, RelationRecord{
660	+					RecordType:   "relation",
661	+					FromID:       symbol.ContainerID,
662	+					ToID:         symbol.ID,
663	+					Type:         "CONTAINS",
664	+					Confidence:   1,
665	+					Reason:       "symbol qualified name is nested in container",
666	+					WarningCodes: []string{},
667	+				})
668	+			}
669	+			symbolsByShortName[symbol.Name] = append(symbolsByShortName[symbol.Name], symbol)
670	+		}
671	+	}
672	+
673	+	for _, file := range files {
674	+		contentBytes, err := os.ReadFile(filepath.Join(repo, filepath.FromSlash(file.Path)))
675	+		if err != nil {
676	+			continue
677	+		}
678	+		content := string(contentBytes)
679	+		fromID := fileID(repoKey, file.Path)
680	+		for _, imported := range importsFor(file.Path, content) {
681	+			relations = append(relations, RelationRecord{
682	+				RecordType:   "relation",
683	+				FromID:       fromID,
684	+				ToID:         externalID("import", imported),
685	+				Type:         "IMPORTS",
686	+				Confidence:   0.8,
687	+				Reason:       "import declaration matched by language-specific scanner",
688	+				WarningCodes: []string{},
689	+			})
690	+		}
691	+		for _, from := range recordsByFile[file.Path] {
692	+			block := symbolBlock(content, from)
693	+			for name, candidates := range symbolsByShortName {
694	+				if name == from.Name || !containsIdentifier(block, name) {
695	+					continue
696	+				}
697	+				for _, to := range candidates {
698	+					if to.ID == from.ID {
699	+						continue
700	+					}
701	+					relations = append(relations, RelationRecord{
702	+						RecordType:   "relation",
703	+						FromID:       from.ID,
704	+						ToID:         to.ID,
705	+						Type:         "CALLS",
706	+						Confidence:   0.62,
707	+						Reason:       "identifier reference inside symbol body matches known symbol name",
708	+						WarningCodes: []string{},
709	+					})
710	+				}
711	+			}
712	+			for _, route := range routeLiterals(block) {
713	+				relations = append(relations, RelationRecord{
714	+					RecordType:   "relation",
715	+					FromID:       from.ID,
716	+					ToID:         externalID("route", route),
717	+					Type:         "HANDLES_ROUTE",
718	+					Confidence:   0.7,
719	+					Reason:       "route-like string literal found inside handler symbol",
720	+					WarningCodes: []string{},
721	+				})
722	+			}
723	+			if looksLikeToolHandler(from, block) {
724	+				relations = append(relations, RelationRecord{
725	+					RecordType:   "relation",
726	+					FromID:       from.ID,
727	+					ToID:         externalID("tool", from.QualifiedName),
728	+					Type:         "HANDLES_TOOL",
729	+					Confidence:   0.58,
730	+					Reason:       "symbol name or body contains tool handler vocabulary",
731	+					WarningCodes: []string{},
732	+				})
733	+			}
734	+		}
735	+	}
736	+
737	+	sort.Slice(relations, func(i, j int) bool {
738	+		left := relations[i].Type + relations[i].FromID + relations[i].ToID
739	+		right := relations[j].Type + relations[j].FromID + relations[j].ToID
740	+		return left < right
741	+	})
742	+	return dedupeRelations(relations)
743	+}
