745	+func workingTreeFiles(repo string) ([]string, error) {
746	+	var paths []string
747	+	err := filepath.WalkDir(repo, func(path string, entry fs.DirEntry, err error) error {
748	+		if err != nil {
749	+			return err
750	+		}
751	+		name := entry.Name()
752	+		if entry.IsDir() {
753	+			switch name {
754	+			case ".git", "node_modules", "vendor", ".next", "dist", "build":
755	+				return filepath.SkipDir
756	+			}
757	+			return nil
758	+		}
759	+		if entry.Type()&fs.ModeSymlink != 0 {
760	+			return nil
761	+		}
762	+		rel, err := filepath.Rel(repo, path)
763	+		if err != nil {
764	+			return err
765	+		}
766	+		paths = append(paths, filepath.ToSlash(rel))
767	+		return nil
768	+	})
769	+	sort.Strings(paths)
770	+	return paths, err
771	+}
772	+
773	+func importsFor(path, content string) []string {
774	+	switch strings.ToLower(filepath.Ext(path)) {
775	+	case ".go":
776	+		return scanImports(content, regexp.MustCompile(`(?m)^\s*import\s+(?:\w+\s+)?["]([^"]+)["]`), regexp.MustCompile(`(?m)^\s*(?:\w+\s+)?["]([^"]+)["]`))
777	+	case ".py":
778	+		return scanImports(content, regexp.MustCompile(`(?m)^\s*(?:from\s+([A-Za-z0-9_\.]+)\s+import|import\s+([A-Za-z0-9_\.]+))`))
779	+	case ".js", ".jsx", ".ts", ".tsx":
780	+		return scanImports(content, regexp.MustCompile(`(?m)^\s*import\s+.*?\s+from\s+['"]([^'"]+)['"]|^\s*import\s+['"]([^'"]+)['"]`))
781	+	case ".rs":
782	+		return scanImports(content, regexp.MustCompile(`(?m)^\s*use\s+([^;]+);`))
783	+	default:
784	+		return nil
785	+	}
786	+}
787	+
788	+func scanImports(content string, expressions ...*regexp.Regexp) []string {
789	+	seen := map[string]struct{}{}
790	+	scanner := bufio.NewScanner(strings.NewReader(content))
791	+	for scanner.Scan() {
792	+		line := scanner.Text()
793	+		for _, expression := range expressions {
794	+			matches := expression.FindStringSubmatch(line)
795	+			if len(matches) == 0 {
796	+				continue
797	+			}
798	+			for _, match := range matches[1:] {
799	+				if match == "" {
800	+					continue
801	+				}
802	+				seen[strings.TrimSpace(match)] = struct{}{}
803	+			}
804	+		}
805	+	}
806	+	return sortedKeys(seen)
807	+}
808	+
809	+func routeLiterals(content string) []string {
810	+	re := regexp.MustCompile(`["'](/[A-Za-z0-9_\-/{}/:.]*)["']`)
811	+	seen := map[string]struct{}{}
812	+	for _, match := range re.FindAllStringSubmatch(content, -1) {
813	+		if len(match) > 1 {
814	+			seen[match[1]] = struct{}{}
815	+		}
816	+	}
817	+	return sortedKeys(seen)
818	+}
