820	+func looksLikeToolHandler(symbol SymbolRecord, block string) bool {
821	+	value := strings.ToLower(symbol.QualifiedName + "\n" + block)
822	+	return strings.Contains(value, "tool") && (strings.Contains(value, "handler") || strings.Contains(value, "execute") || strings.Contains(value, "schema"))
823	+}
824	+
825	+func symbolBlock(content string, symbol SymbolRecord) string {
826	+	lines := strings.Split(content, "\n")
827	+	start := symbol.StartLine - 1
828	+	if start < 0 {
829	+		start = 0
830	+	}
831	+	end := symbol.EndLine
832	+	if end > len(lines) {
833	+		end = len(lines)
834	+	}
835	+	if end <= start {
836	+		return ""
837	+	}
838	+	return strings.Join(lines[start:end], "\n")
839	+}
