841	+func completenessLevel(failures, files int) string {
842	+	switch {
843	+	case failures == 0:
844	+		return "ok"
845	+	case files == 0 || failures*4 > files:
846	+		return "unsafe"
847	+	default:
848	+		return "degraded"
849	+	}
850	+}
