852	+func dedupeRelations(relations []RelationRecord) []RelationRecord {
853	+	seen := map[string]struct{}{}
854	+	out := make([]RelationRecord, 0, len(relations))
855	+	for _, relation := range relations {
856	+		key := relation.FromID + "\x00" + relation.ToID + "\x00" + relation.Type
857	+		if _, ok := seen[key]; ok {
858	+			continue
859	+		}
860	+		seen[key] = struct{}{}
861	+		out = append(out, relation)
862	+	}
863	+	return out
864	+}
