16	type Options struct {
17		Version string
18		Env     EntireEnv
19		Stdout  io.Writer
20		Stderr  io.Writer
21	}
22	
23	func Execute(version string, args []string) error {
24		return Run(context.Background(), Options{
25			Version: version,
26			Env:     EnvFromOS(),
27			Stdout:  os.Stdout,
28			Stderr:  os.Stderr,
29		}, args)
30	}
31	
32	func Run(ctx context.Context, opts Options, args []string) error {
33		if opts.Version == "" {
34			opts.Version = "dev"
35		}
36		if opts.Stdout == nil {
37			opts.Stdout = io.Discard
38		}
39		if opts.Stderr == nil {
40			opts.Stderr = io.Discard
41		}
42	
43		if len(args) == 0 {
44			printHelp(opts.Stdout)
45			return nil
46		}
47	
48		switch args[0] {
49		case "diff":
50			return runDiff(ctx, opts, args[1:])
51		case "commit":
52			return runCommit(ctx, opts, args[1:])
53		case "checkpoint":
54			return runCheckpoint(ctx, opts, args[1:])
55		case "analyze":
56			return runAnalyze(ctx, opts, args[1:])
57		case "doctor":
58			return runDoctor(ctx, opts, args[1:])
59		case "capabilities":
60			return runCapabilities(opts, args[1:])
61		case "snapshot":
62			return runProviderRecords(ctx, opts, args[1:], "snapshot")
63		case "symbols":
64			return runProviderRecords(ctx, opts, args[1:], "symbols")
65		case "edges":
66			return runProviderRecords(ctx, opts, args[1:], "edges")
67		case "version", "--version", "-v":
68			if len(args) > 1 && args[1] == "--json" {
69				return json.NewEncoder(opts.Stdout).Encode(map[string]string{
70					"provider": sem.ProviderName,
71					"version":  opts.Version,
72				})
73			}
74			fmt.Fprintln(opts.Stdout, opts.Version)
75			return nil
76		case "help", "--help", "-h":
77			printHelp(opts.Stdout)
78			return nil
79		default:
80			return fmt.Errorf("unknown command %q", args[0])
81		}
82	}
83	
84	func printHelp(out io.Writer) {
85		fmt.Fprintln(out, `entire-sem adds entity-level context to Entire checkpoints.
86	
87	Usage:
88	  entire sem commit [rev] [--json] [--repo path]
89	  entire sem checkpoint <checkpoint-id> [--json] [--repo path]
90	  entire sem diff --base <rev> --head <rev> [--json] [--repo path] [-- path...]
91	  entire sem analyze [--base <rev>] [--head <rev>] [--json] [--repo path] [-- path...]
92	  entire sem doctor [--json]
93	  entire sem version [--json]
94	  entire sem capabilities --json
95	  entire sem snapshot --repo . --format ndjson
96	  entire sem symbols --repo . --format ndjson
97	  entire sem edges --repo . --format ndjson`)
98	}
