100	func runDoctor(ctx context.Context, opts Options, args []string) error {
101		asJSON := len(args) == 1 && args[0] == "--json"
102		if len(args) > 1 || (len(args) == 1 && !asJSON) {
103			return errors.New("doctor accepts only --json")
104		}
105		report := map[string]any{
106			"provider": sem.ProviderName,
107			"version":  opts.Version,
108			"environment": map[string]string{
109				envCLIVersion:    valueOrUnset(opts.Env.CLIVersion),
110				envRepoRoot:      valueOrUnset(opts.Env.RepoRoot),
111				envPluginDataDir: valueOrUnset(opts.Env.PluginDataDir),
112			},
113			"phase_1_local_only": map[string]bool{
114				"fetch_remote_code":              false,
115				"download_grammars_or_assets":    false,
116				"upload_telemetry":               false,
117				"call_hosted_model_apis":         false,
118				"call_remote_embedding_provider": false,
