120			},
121		}
122		if !asJSON {
123			fmt.Fprintf(opts.Stdout, "ENTIRE_CLI_VERSION=%s\n", valueOrUnset(opts.Env.CLIVersion))
124			fmt.Fprintf(opts.Stdout, "ENTIRE_REPO_ROOT=%s\n", valueOrUnset(opts.Env.RepoRoot))
125			fmt.Fprintf(opts.Stdout, "ENTIRE_PLUGIN_DATA_DIR=%s\n", valueOrUnset(opts.Env.PluginDataDir))
126		}
127	
128		if opts.Env.PluginDataDir != "" {
129			if err := os.MkdirAll(opts.Env.PluginDataDir, 0o700); err != nil {
130				return fmt.Errorf("create plugin data dir: %w", err)
