138				return fmt.Errorf("close plugin data probe: %w", err)
139			}
140			if err := os.Remove(probeName); err != nil {
141				return fmt.Errorf("remove plugin data probe: %w", err)
142			}
143			report["plugin_data_dir"] = "writable"
144			if !asJSON {
145				fmt.Fprintln(opts.Stdout, "plugin_data_dir=writable")
146			}
147		}
148	
149		repo, err := resolveRepo(ctx, opts.Env, "")
150		if err != nil {
151			report["repo_root"] = ""
152			report["repo_error"] = err.Error()
153			if asJSON {
154				return json.NewEncoder(opts.Stdout).Encode(report)
155			}
156			fmt.Fprintf(opts.Stdout, "repo_root=%s\n", valueOrUnset(""))
157			fmt.Fprintf(opts.Stdout, "repo_error=%s\n", err)
158			return nil
159		}
160		report["repo_root"] = repo
161		if asJSON {
162			return json.NewEncoder(opts.Stdout).Encode(report)
163		}
164		fmt.Fprintf(opts.Stdout, "repo_root=%s\n", repo)
165		return nil
166	}
167	
168	func runCapabilities(opts Options, args []string) error {
169		if len(args) != 1 || args[0] != "--json" {
170			return errors.New("capabilities requires --json")
171		}
172		return json.NewEncoder(opts.Stdout).Encode(sem.Capabilities())
173	}
174	
175	func runProviderRecords(ctx context.Context, opts Options, args []string, mode string) error {
176		flags, rest, err := parseProviderFlags(args)
177		if err != nil {
178			return err
179		}
180		if len(rest) != 0 {
181			return fmt.Errorf("%s received unexpected arguments: %s", mode, strings.Join(rest, " "))
182		}
183		if flags.Format != "ndjson" {
184			return fmt.Errorf("%s requires --format ndjson", mode)
185		}
186		repo, err := resolveRepo(ctx, opts.Env, flags.Repo)
187		if err != nil {
188			return err
189		}
190		snapshot, err := sem.BuildProviderSnapshot(ctx, repo, opts.Version)
191		if err != nil {
192			return err
193		}
194		switch mode {
195		case "snapshot":
196			return sem.WriteSnapshotNDJSON(opts.Stdout, snapshot)
197		case "symbols":
198			return sem.WriteSymbolsNDJSON(opts.Stdout, snapshot)
199		case "edges":
200			return sem.WriteRelationsNDJSON(opts.Stdout, snapshot)
201		default:
202			return fmt.Errorf("unknown provider record mode %q", mode)
203		}
204	}
205	
206	type commonFlags struct {
207		Repo string
208		JSON bool
209	}
210	
211	type providerFlags struct {
212		Repo   string
213		Format string
214	}
215	
216	func parseProviderFlags(args []string) (providerFlags, []string, error) {
217		flags := providerFlags{Format: "ndjson"}
218		var rest []string
219		for i := 0; i < len(args); i++ {
220			switch args[i] {
221			case "--repo":
222				i++
223				if i >= len(args) {
224					return flags, nil, errors.New("--repo requires a value")
225				}
226				flags.Repo = args[i]
227			case "--format":
228				i++
229				if i >= len(args) {
230					return flags, nil, errors.New("--format requires a value")
231				}
232				flags.Format = args[i]
233			default:
234				rest = append(rest, args[i])
235			}
236		}
237		return flags, rest, nil
238	}
239	
240	func parseCommonFlags(args []string) (commonFlags, []string, error) {
241		var flags commonFlags
242		var rest []string
243		for i := 0; i < len(args); i++ {
244			arg := args[i]
245			switch arg {
246			case "--json":
247				flags.JSON = true
248			case "--repo":
249				i++
250				if i >= len(args) {
251					return flags, nil, errors.New("--repo requires a value")
252				}
253				flags.Repo = args[i]
254			case "--":
255				rest = append(rest, args[i+1:]...)
256				return flags, rest, nil
257			default:
258				rest = append(rest, arg)
259			}
260		}
261		return flags, rest, nil
262	}
263	
264	func runCommit(ctx context.Context, opts Options, args []string) error {
265		flags, rest, err := parseCommonFlags(args)
266		if err != nil {
267			return err
268		}
269		rev := "HEAD"
270		if len(rest) > 0 {
271			rev = rest[0]
272		}
273		if len(rest) > 1 {
274			return errors.New("commit accepts at most one revision")
275		}
276		repo, err := resolveRepo(ctx, opts.Env, flags.Repo)
277		if err != nil {
278			return err
279		}
280		base, err := gitutil.FirstParent(ctx, repo, rev)
281		if err != nil {
282			return err
