137	func Capabilities() CapabilityReport {
138		extensions := make([]string, 0, len(treeSitterLanguages))
139		languageSet := map[string]struct{}{}
140		for extension, spec := range treeSitterLanguages {
141			extensions = append(extensions, extension)
142			languageSet[spec.language] = struct{}{}
143		}
144		sort.Strings(extensions)
145		languages := make([]string, 0, len(languageSet))
146		for language := range languageSet {
147			languages = append(languages, language)
148		}
149		sort.Strings(languages)
150	
151		return CapabilityReport{
152			SchemaVersion:                   SchemaVersion,
153			Provider:                        ProviderName,
154			SupportedFileExtensions:         extensions,
155			SupportedLanguages:              languages,
156			UnsupportedButDetectedLanguages: []string{},
157			ParserVersions: map[string]string{
158				"go-tree-sitter": "github.com/smacker/go-tree-sitter",
159			},
160			SupportedRelationTypes: append([]string(nil), relationTypes...),
161			OptionalLocalOnlyFeatures: map[string]bool{
162				"stable_symbol_ids": true,
163				"semantic_diff":     true,
164				"ndjson_snapshot":   true,
165			},
166			FeaturesRequiringNetworkAccess: map[string]bool{
167				"grammar_download":  false,
168				"hosted_models":     false,
169				"remote_embeddings": false,
170				"telemetry_upload":  false,
171				"remote_code_fetch": false,
172				"network_discovery": false,
173			},
174		}
175	}
176	
177	func BuildProviderSnapshot(ctx context.Context, repo, providerVersion string) (ProviderSnapshot, error) {
178		absRepo, err := filepath.Abs(repo)
179		if err != nil {
180			return ProviderSnapshot{}, err
181		}
182		repoKey := repoKey(absRepo)
183		var warnings []ProviderWarning
184		commit, commitErr := gitutil.RevParse(ctx, absRepo, "HEAD")
185		tree, treeErr := gitutil.RevParse(ctx, absRepo, "HEAD^{tree}")
186	
187		paths, contentByFile, err := snapshotSource(ctx, absRepo, commitErr == nil && treeErr == nil)
188		if err != nil {
189			return ProviderSnapshot{}, err
190		}
191		if commitErr != nil || treeErr != nil {
192			warnings = append(warnings, ProviderWarning{
193				Code:                 "E_NO_GIT_HEAD",
194				Severity:             "warning",
195				EffectOnCompleteness: "snapshot records are read from the working tree because no HEAD tree is available",
196				Detail:               firstError(commitErr, treeErr).Error(),
197			})
198		}
199	
200		parser := TreeSitterParser{}
201		languageSet := map[string]struct{}{}
202		var files []FileRecord
203		var symbols []SymbolRecord
204		var failures []PartialFailure
205		recordsByFile := map[string][]SymbolRecord{}
206	
207		for _, path := range paths {
208			if !Supported(path) {
209				continue
210			}
211			content, ok := contentByFile[path]
212			if !ok {
213				failures = append(failures, PartialFailure{
214					Code:                 "E_FILE_READ",
215					Severity:             "error",
216					FilePath:             path,
217					EffectOnCompleteness: "file omitted from semantic snapshot",
218					Detail:               "file listed but content was unavailable",
219				})
220				continue
221			}
222			entities, language := parser.Parse(path, content)
223			if language == "" {
224				failures = append(failures, PartialFailure{
225					Code:                 "E_UNSUPPORTED_LANGUAGE",
226					Severity:             "warning",
227					FilePath:             path,
228					EffectOnCompleteness: "file omitted because no parser is available",
229				})
230				continue
231			}
232			languageSet[language] = struct{}{}
233			contentBytes := []byte(content)
234			files = append(files, FileRecord{
235				RecordType: "file",
236				Path:       path,
237				Blob:       contentHash(contentBytes),
238				Language:   language,
239				Bytes:      len(contentBytes),
240			})
241			fileSymbols := entitySymbols(repoKey, path, language, entities)
242			symbols = append(symbols, fileSymbols...)
243			recordsByFile[path] = fileSymbols
244		}
245	
246		relations := buildRelations(repoKey, files, recordsByFile, contentByFile)
247		languages := sortedKeys(languageSet)
248		if warnings == nil {
249			warnings = []ProviderWarning{}
250		}
251		if failures == nil {
252			failures = []PartialFailure{}
253		}
254		header := SnapshotHeader{
255			SchemaVersion:   SchemaVersion,
256			Provider:        ProviderName,
257			ProviderVersion: providerVersion,
258			RepoRoot:        absRepo,
259			RepoKey:         repoKey,
260			Commit:          commit,
261			Tree:            tree,
262			Languages:       languages,
263			Capabilities:    []string{"ndjson", "stable-symbol-id-v1", "local-only", "partial-failures"},
264			Warnings:        warnings,
265			PartialFailures: failures,
266			Stats: ProviderStats{
267				Files:             len(files),
268				ParsedFiles:       len(recordsByFile),
269				Symbols:           len(symbols),
270				Relations:         len(relations),
271				PartialFailures:   len(failures),
272				CompletenessLevel: completenessLevel(len(failures), len(files)),
273			},
274		}
275		return ProviderSnapshot{Header: header, Files: files, Symbols: symbols, Relations: relations}, nil
276	}
277	
278	func WriteSnapshotNDJSON(out io.Writer, snapshot ProviderSnapshot) error {
279		if err := writeJSONLine(out, snapshot.Header); err != nil {
280			return err
281		}
282		for _, record := range snapshot.Files {
283			if err := writeJSONLine(out, record); err != nil {
284				return err
285			}
286		}
287		for _, record := range snapshot.Symbols {
288			if err := writeJSONLine(out, record); err != nil {
289				return err
290			}
291		}
292		for _, record := range snapshot.Relations {
293			if err := writeJSONLine(out, record); err != nil {
294				return err
295			}
296		}
297		return nil
298	}
299	
300	func WriteSymbolsNDJSON(out io.Writer, snapshot ProviderSnapshot) error {
301		for _, record := range snapshot.Symbols {
302			if err := writeJSONLine(out, record); err != nil {
303				return err
304			}
305		}
306		return nil
307	}
308	
309	func WriteRelationsNDJSON(out io.Writer, snapshot ProviderSnapshot) error {
310		for _, record := range snapshot.Relations {
311			if err := writeJSONLine(out, record); err != nil {
312				return err
313			}
314		}
315		return nil
316	}
317	
318	func entitySymbols(repoKey, path, language string, entities []Entity) []SymbolRecord {
319		byName := map[string]string{}
320		var symbols []SymbolRecord
321		for _, entity := range entities {
322			qualified := entity.Name
323			id := symbolID(repoKey, language, path, entity.Kind, qualified)
324			containerID := ""
325			if containerName := containerName(qualified); containerName != "" {
326				if parentID, ok := byName[containerName]; ok {
327					containerID = parentID
328				}
329			}
330			symbol := SymbolRecord{
331				RecordType:      "symbol",
332				ID:              id,
333				StableIDVersion: StableSymbolIDVersion,
334				Kind:            entity.Kind,
335				Name:            shortEntityName(entity.Name),
336				QualifiedName:   qualified,
337				FilePath:        path,
338				StartLine:       entity.StartLine,
339				EndLine:         entity.EndLine,
340				Signature:       entity.Signature,
341				BodyHash:        entity.BodyHash,
342				Language:        language,
343				ContainerID:     containerID,
344			}
345			symbols = append(symbols, symbol)
346			byName[qualified] = id
347		}
348		return symbols
349	}
350	
351	func buildRelations(repoKey string, files []FileRecord, recordsByFile map[string][]SymbolRecord, contentByFile map[string]string) []RelationRecord {
352		var relations []RelationRecord
353		symbolsByShortName := map[string][]SymbolRecord{}
354		for _, records := range recordsByFile {
355			for _, symbol := range records {
356				relations = append(relations, RelationRecord{
357					RecordType:   "relation",
358					FromID:       fileID(repoKey, symbol.FilePath),
359					ToID:         symbol.ID,
360					Type:         "DEFINES",
361					Confidence:   1,
362					Reason:       "symbol parsed from file",
363					WarningCodes: []string{},
364				})
365				if symbol.ContainerID != "" {
366					relations = append(relations, RelationRecord{
367						RecordType:   "relation",
368						FromID:       symbol.ContainerID,
369						ToID:         symbol.ID,
370						Type:         "CONTAINS",
371						Confidence:   1,
372						Reason:       "symbol qualified name is nested in container",
373						WarningCodes: []string{},
374					})
375				}
376				symbolsByShortName[symbol.Name] = append(symbolsByShortName[symbol.Name], symbol)
377			}
378		}
379	
380		for _, file := range files {
381			content, ok := contentByFile[file.Path]
382			if !ok {
383				continue
384			}
385			fromID := fileID(repoKey, file.Path)
386			for _, imported := range importsFor(file.Path, content) {
387				relations = append(relations, RelationRecord{
388					RecordType:   "relation",
389					FromID:       fromID,
390					ToID:         externalID("import", imported),
391					Type:         "IMPORTS",
392					Confidence:   0.8,
393					Reason:       "import declaration matched by language-specific scanner",
394					WarningCodes: []string{},
395				})
396			}
397			for _, from := range recordsByFile[file.Path] {
398				block := symbolBlock(content, from)
399				for name, candidates := range symbolsByShortName {
400					if name == from.Name || !containsIdentifier(block, name) {
401						continue
402					}
403					for _, to := range candidates {
404						if to.ID == from.ID {
405							continue
406						}
407						relations = append(relations, RelationRecord{
408							RecordType:   "relation",
409							FromID:       from.ID,
410							ToID:         to.ID,
411							Type:         "CALLS",
412							Confidence:   0.62,
413							Reason:       "identifier reference inside symbol body matches known symbol name",
414							WarningCodes: []string{},
415						})
416					}
417				}
418				for _, route := range routeLiterals(block) {
419					relations = append(relations, RelationRecord{
420						RecordType:   "relation",
421						FromID:       from.ID,
422						ToID:         externalID("route", route),
423						Type:         "HANDLES_ROUTE",
424						Confidence:   0.7,
425						Reason:       "route-like string literal found inside handler symbol",
426						WarningCodes: []string{},
427					})
428				}
429				if looksLikeToolHandler(from, block) {
430					relations = append(relations, RelationRecord{
431						RecordType:   "relation",
432						FromID:       from.ID,
433						ToID:         externalID("tool", from.QualifiedName),
434						Type:         "HANDLES_TOOL",
435						Confidence:   0.58,
436						Reason:       "symbol name or body contains tool handler vocabulary",
437						WarningCodes: []string{},
438					})
439				}
440			}
441		}
442	
443		sort.Slice(relations, func(i, j int) bool {
444			left := relations[i].Type + relations[i].FromID + relations[i].ToID
445			right := relations[j].Type + relations[j].FromID + relations[j].ToID
446			return left < right
447		})
448		return dedupeRelations(relations)
449	}
450	
451	func snapshotSource(ctx context.Context, repo string, useHead bool) ([]string, map[string]string, error) {
452		if useHead {
453			paths, err := gitutil.ListFiles(ctx, repo, "HEAD")
454			if err != nil {
455				return nil, nil, err
456			}
457			contentByFile := map[string]string{}
458			for _, path := range paths {
459				content, ok, err := gitutil.ShowFile(ctx, repo, "HEAD", path)
460				if err != nil {
461					return nil, nil, err
462				}
463				if ok {
464					contentByFile[path] = content
465				}
466			}
467			return paths, contentByFile, nil
468		}
469		paths, err := workingTreeFiles(repo)
470		if err != nil {
471			return nil, nil, err
472		}
473		contentByFile := map[string]string{}
474		for _, path := range paths {
475			content, err := os.ReadFile(filepath.Join(repo, filepath.FromSlash(path)))
476			if err != nil {
477				continue
478			}
479			contentByFile[path] = string(content)
480		}
481		return paths, contentByFile, nil
482	}
483	
484	func workingTreeFiles(repo string) ([]string, error) {
485		var paths []string
486		err := filepath.WalkDir(repo, func(path string, entry fs.DirEntry, err error) error {
487			if err != nil {
488				return err
489			}
490			name := entry.Name()
491			if entry.IsDir() {
492				switch name {
493				case ".git", "node_modules", "vendor", ".next", "dist", "build":
494					return filepath.SkipDir
495				}
496				return nil
497			}
498			if entry.Type()&fs.ModeSymlink != 0 {
499				return nil
500			}
501			rel, err := filepath.Rel(repo, path)
502			if err != nil {
503				return err
504			}
505			paths = append(paths, filepath.ToSlash(rel))
506			return nil
507		})
508		sort.Strings(paths)
509		return paths, err
510	}
511	
512	func firstError(errs ...error) error {
513		for _, err := range errs {
514			if err != nil {
515				return err
516			}
517		}
518		return nil
519	}
520	
521	func importsFor(path, content string) []string {
522		switch strings.ToLower(filepath.Ext(path)) {
523		case ".go":
524			return scanImports(content, regexp.MustCompile(`(?m)^\s*import\s+(?:\w+\s+)?["]([^"]+)["]`), regexp.MustCompile(`(?m)^\s*(?:\w+\s+)?["]([^"]+)["]`))
525		case ".py":
526			return scanImports(content, regexp.MustCompile(`(?m)^\s*(?:from\s+([A-Za-z0-9_\.]+)\s+import|import\s+([A-Za-z0-9_\.]+))`))
527		case ".js", ".jsx", ".ts", ".tsx":
528			return scanImports(content, regexp.MustCompile(`(?m)^\s*import\s+.*?\s+from\s+['"]([^'"]+)['"]|^\s*import\s+['"]([^'"]+)['"]`))
529		case ".rs":
530			return scanImports(content, regexp.MustCompile(`(?m)^\s*use\s+([^;]+);`))
531		default:
532			return nil
533		}
534	}
535	
536	func scanImports(content string, expressions ...*regexp.Regexp) []string {
537		seen := map[string]struct{}{}
538		scanner := bufio.NewScanner(strings.NewReader(content))
539		for scanner.Scan() {
540			line := scanner.Text()
541			for _, expression := range expressions {
542				matches := expression.FindStringSubmatch(line)
543				if len(matches) == 0 {
544					continue
545				}
546				for _, match := range matches[1:] {
547					if match == "" {
548						continue
549					}
550					seen[strings.TrimSpace(match)] = struct{}{}
551				}
552			}
553		}
554		return sortedKeys(seen)
555	}
556	
557	func routeLiterals(content string) []string {
558		re := regexp.MustCompile(`["'](/[A-Za-z0-9_\-/{}/:.]*)["']`)
559		seen := map[string]struct{}{}
560		for _, match := range re.FindAllStringSubmatch(content, -1) {
561			if len(match) > 1 {
562				seen[match[1]] = struct{}{}
563			}
564		}
565		return sortedKeys(seen)
566	}
567	
568	func looksLikeToolHandler(symbol SymbolRecord, block string) bool {
569		value := strings.ToLower(symbol.QualifiedName + "\n" + block)
570		return strings.Contains(value, "tool") && (strings.Contains(value, "handler") || strings.Contains(value, "execute") || strings.Contains(value, "schema"))
571	}
572	
573	func symbolBlock(content string, symbol SymbolRecord) string {
574		lines := strings.Split(content, "\n")
575		start := symbol.StartLine - 1
576		if start < 0 {
577			start = 0
578		}
579		end := symbol.EndLine
580		if end > len(lines) {
581			end = len(lines)
582		}
583		if end <= start {
584			return ""
585		}
586		return strings.Join(lines[start:end], "\n")
587	}
588	
589	func completenessLevel(failures, files int) string {
590		switch {
591		case failures == 0:
592			return "ok"
593		case files == 0 || failures*4 > files:
594			return "unsafe"
595		default:
596			return "degraded"
597		}
598	}
599	
600	func dedupeRelations(relations []RelationRecord) []RelationRecord {
601		seen := map[string]struct{}{}
602		out := make([]RelationRecord, 0, len(relations))
603		for _, relation := range relations {
604			key := relation.FromID + "\x00" + relation.ToID + "\x00" + relation.Type
605			if _, ok := seen[key]; ok {
606				continue
607			}
608			seen[key] = struct{}{}
609			out = append(out, relation)
610		}
611		return out
612	}
613	
614	func writeJSONLine(out io.Writer, value any) error {
615		encoded, err := json.Marshal(value)
616		if err != nil {
617			return err
618		}
619		_, err = fmt.Fprintln(out, string(encoded))
620		return err
621	}
622	
623	func symbolID(repoKey, language, path, kind, qualifiedName string) string {
624		return strings.Join([]string{repoKey, language, path, kind, qualifiedName}, ":")
625	}
626	
627	func fileID(repoKey, path string) string {
628		return repoKey + ":file:" + path
629	}
630	
631	func externalID(kind, value string) string {
632		return "external:" + kind + ":" + value
633	}
634	
635	func repoKey(repo string) string {
636		return "local/" + filepath.Base(repo)
637	}
638	
639	func containerName(qualifiedName string) string {
640		index := strings.LastIndex(qualifiedName, ".")
641		if index < 0 {
642			return ""
643		}
644		return qualifiedName[:index]
645	}
646	
647	func contentHash(content []byte) string {
648		sum := sha256.Sum256(content)
649		return hex.EncodeToString(sum[:])
650	}
651	
652	func sortedKeys(set map[string]struct{}) []string {
653		out := make([]string, 0, len(set))
654		for key := range set {
655			out = append(out, key)
656		}
657		sort.Strings(out)
658		return out
659	}
